query:
CREATE TABLE IF NOT EXISTS `favourites` (
  `id` bigint AUTO_INCREMENT NOT NULL,
  `user_id` bigint NOT NULL,
  `sitter_id` bigint NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT `favourites_id` PRIMARY KEY(`id`),
  CONSTRAINT `fk_fav_user` FOREIGN KEY (`user_id`) REFERENCES `users`(`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_fav_sitter` FOREIGN KEY (`sitter_id`) REFERENCES `users`(`id`) ON DELETE CASCADE
);
CREATE INDEX `fav_user_idx` ON `favourites` (`user_id`);
CREATE INDEX `fav_sitter_idx` ON `favourites` (`sitter_id`);
CREATE UNIQUE INDEX `fav_unique_idx` ON `favourites` (`user_id`, `sitter_id`);

